TriggerOraclev10g.body:
DECLARE 
envbq_status number;
valor_envbq_update number;
vro_error  tkr_errores%ROWTYPE;
BEGIN
    -- Caso INSERT
    IF INSERTING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_SERVICIOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_SERVICIOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1;
       END IF;        

        INSERT INTO TKRBQ_SERVICIOS (
            ENVIO_BQ, ID, NOMBRE_SERVICIO, FECHA_CREACION, ID_CLASE_CITA
        )
        VALUES (
            0, -- ENVIO_BQ para INSERT
            :NEW.ID, :NEW.NOMBRE_SERVICIO, :NEW.FECHA_CREACION, :NEW.ID_CLASE_CITA
        );
    END IF;

    -- Caso UPDATE
    IF UPDATING THEN
        SELECT (SELECT ENVIO_BQ FROM TKRBQ_SERVICIOS WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NULL THEN

            INSERT INTO TKRBQ_SERVICIOS (
                ENVIO_BQ, ID, NOMBRE_SERVICIO, FECHA_CREACION, ID_CLASE_CITA
            )
            VALUES (
                2, -- ENVIO_BQ para INSERT
                :NEW.ID, :NEW.NOMBRE_SERVICIO, :NEW.FECHA_CREACION, :NEW.ID_CLASE_CITA
            );       

       ELSE

            IF envbq_status = 0 THEN 
                valor_envbq_update := 0;
            ELSE
                valor_envbq_update := 2;
            END IF;    

            UPDATE TKRBQ_SERVICIOS
            SET
                ENVIO_BQ = valor_envbq_update,
                ID = :NEW.ID,
                NOMBRE_SERVICIO = :NEW.NOMBRE_SERVICIO,
                FECHA_CREACION = :NEW.FECHA_CREACION,
                ID_CLASE_CITA = :NEW.ID_CLASE_CITA
            WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
        END IF;
    END IF;

    -- Caso DELETE
    IF DELETING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_SERVICIOS WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_SERVICIOS WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
       END IF;        

        INSERT INTO TKRBQ_SERVICIOS (
            ENVIO_BQ, ID, NOMBRE_SERVICIO, FECHA_CREACION, ID_CLASE_CITA
        )
        VALUES (
            -1, -- ENVIO_BQ para DELETE
            :OLD.ID, :OLD.NOMBRE_SERVICIO, :OLD.FECHA_CREACION, :OLD.ID_CLASE_CITA
        );
    END IF;

    EXCEPTION
        WHEN OTHERS
        THEN
            vro_error.nombre_programa := 'TRG_SYNC_TKR_SERVICIOS';
            vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ';
            vro_error.parametros := 'id de consultas: '||:old.id;
            uti_ge_excepciones_pkg.p_grabar_log (vro_error);

END;
